2803 /// This is the underlying implementation of all of the
2804 /// ConstantDataSequential::get methods.  They all thunk down to here, providing
2805 /// the correct element type.  We take the bytes in as a StringRef because
2806 /// we *want* an underlying "char*" to avoid TBAA type punning violations.
2807 Constant *ConstantDataSequential::getImpl(StringRef Elements, Type *Ty) {
2808 #ifndef NDEBUG
2809   if (ArrayType *ATy = dyn_cast<ArrayType>(Ty))
2810     assert(isElementTypeCompatible(ATy->getElementType()));
2811   else
2812     assert(isElementTypeCompatible(cast<VectorType>(Ty)->getElementType()));
2813 #endif
2814   // If the elements are all zero or there are no elements, return a CAZ, which
2815   // is more dense and canonical.
2816   if (isAllZeros(Elements))
2817     return ConstantAggregateZero::get(Ty);
2818 
2819   // Do a lookup to see if we have already formed one of these.
2820   auto &Slot =
2821       *Ty->getContext()
2822            .pImpl->CDSConstants.insert(std::make_pair(Elements, nullptr))
2823            .first;
2824 
2825   // The bucket can point to a linked list of different CDS's that have the same
2826   // body but different types.  For example, 0,0,0,1 could be a 4 element array
2827   // of i8, or a 1-element array of i32.  They'll both end up in the same
2828   /// StringMap bucket, linked up by their Next pointers.  Walk the list.
2829   std::unique_ptr<ConstantDataSequential> *Entry = &Slot.second;
2830   for (; *Entry; Entry = &(*Entry)->Next)
2831     if ((*Entry)->getType() == Ty)
2832       return Entry->get();
2833 
2834   // Okay, we didn't get a hit.  Create a node of the right class, link it in,
2835   // and return it.
2836   if (isa<ArrayType>(Ty)) {
2837     // Use reset because std::make_unique can't access the constructor.
2838     Entry->reset(new ConstantDataArray(Ty, Slot.first().data()));
2839     return Entry->get();
2840   }
2841 
2842   assert(isa<VectorType>(Ty));
2843   // Use reset because std::make_unique can't access the constructor.
2844   Entry->reset(new ConstantDataVector(Ty, Slot.first().data()));
2845   return Entry->get();
2846 }
