2657 Constant *ConstantExpr::getBinOpIdentity(unsigned Opcode, Type *Ty,
2658                                          bool AllowRHSConstant, bool NSZ) {
2659   assert(Instruction::isBinaryOp(Opcode) && "Only binops allowed");
2660 
2661   // Commutative opcodes: it does not matter if AllowRHSConstant is set.
2662   if (Instruction::isCommutative(Opcode)) {
2663     switch (Opcode) {
2664       case Instruction::Add: // X + 0 = X
2665       case Instruction::Or:  // X | 0 = X
2666       case Instruction::Xor: // X ^ 0 = X
2667         return Constant::getNullValue(Ty);
2668       case Instruction::Mul: // X * 1 = X
2669         return ConstantInt::get(Ty, 1);
2670       case Instruction::And: // X & -1 = X
2671         return Constant::getAllOnesValue(Ty);
2672       case Instruction::FAdd: // X + -0.0 = X
2673         return ConstantFP::getZero(Ty, !NSZ);
2674       case Instruction::FMul: // X * 1.0 = X
2675         return ConstantFP::get(Ty, 1.0);
2676       default:
2677         llvm_unreachable("Every commutative binop has an identity constant");
2678     }
2679   }
2680 
2681   // Non-commutative opcodes: AllowRHSConstant must be set.
2682   if (!AllowRHSConstant)
2683     return nullptr;
2684 
2685   switch (Opcode) {
2686     case Instruction::Sub:  // X - 0 = X
2687     case Instruction::Shl:  // X << 0 = X
2688     case Instruction::LShr: // X >>u 0 = X
2689     case Instruction::AShr: // X >> 0 = X
2690     case Instruction::FSub: // X - 0.0 = X
2691       return Constant::getNullValue(Ty);
2692     case Instruction::SDiv: // X / 1 = X
2693     case Instruction::UDiv: // X /u 1 = X
2694       return ConstantInt::get(Ty, 1);
2695     case Instruction::FDiv: // X / 1.0 = X
2696       return ConstantFP::get(Ty, 1.0);
2697     default:
2698       return nullptr;
2699   }
2700 }
